package dev.yazidcv.identity;
import jakarta.validation.Valid; import jakarta.validation.constraints.*; import org.springframework.beans.factory.annotation.Value; import org.springframework.security.authentication.*; import org.springframework.security.core.Authentication; import org.springframework.security.oauth2.jose.jws.MacAlgorithm; import org.springframework.security.oauth2.jwt.*; import org.springframework.web.bind.annotation.*; import java.time.*; import java.util.*;
@RestController @RequestMapping("/api/v1/auth") public class AuthController{
 private final AuthenticationManager authenticationManager; private final JwtEncoder encoder; private final String issuer;
 public AuthController(AuthenticationManager am,JwtEncoder encoder,@Value("${yazidcv.jwt-issuer}")String issuer){this.authenticationManager=am;this.encoder=encoder;this.issuer=issuer;}
 @PostMapping("/login") public LoginResponse login(@Valid @RequestBody LoginRequest request){Authentication auth=authenticationManager.authenticate(new UsernamePasswordAuthenticationToken(request.email(),request.password()));Instant now=Instant.now();var claims=JwtClaimsSet.builder().issuer(issuer).issuedAt(now).expiresAt(now.plus(Duration.ofHours(8))).subject(auth.getName()).claim("org",TenantContext.DEMO_ORG.toString()).claim("roles",auth.getAuthorities().stream().map(Object::toString).toList()).build();String token=encoder.encode(JwtEncoderParameters.from(JwsHeader.with(MacAlgorithm.HS256).build(),claims)).getTokenValue();return new LoginResponse(token,"Bearer",28800,new UserInfo("Yazid","N.",auth.getName(),"ADMIN","YazidCV Workspace"));}
 public record LoginRequest(@Email @NotBlank String email,@NotBlank String password){} public record UserInfo(String firstName,String lastName,String email,String role,String organization){} public record LoginResponse(String accessToken,String tokenType,long expiresIn,UserInfo user){}
}
